Content: user nginx;
worker_processes 1; events { worker_connections 1024;
} http { sendfile on; tcp_nopush on; tcp_nodelay on; keepalive_timeout 65; types_hash_max_size 2048; include /etc/nginx/mime.types; default_type application/octet-stream; server { listen 80; server_name localhost; location / { # This nginx server is running in a docker compose environment, # so the name "lute" is resolved using compose's dns resolution. proxy_pass http://lute:5000; proxy_set_header Host $host; proxy_set_header X-Real-IP $remote_addr; proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for; proxy_set_header X-Forwarded-Proto $scheme; } # Basic Authentication auth_basic "Restricted Access"; auth_basic_user_file /etc/nginx/.htpasswd; }
}
